// ============================================================================
// Constants
// ============================================================================

/**
 * Default form values for creating a new tag
 */
const DEFAULT_FORM_VALUES: Partial<TagFormData> = {
  name: '',
  color: '',
};

// ============================================================================
// Component
// ============================================================================

/**
 * TagForm Component
 *
 * Renders a form for creating or editing tags.
 * Uses React Hook Form with Controller pattern for form state management.
 *
 * @example
 * ```tsx
 * // Create mode
 * <TagForm
 *   onSubmit={handleCreate}
 *   onCancel={handleCancel}
 *   isLoading={isCreating}
 * />
 *
 * // Edit mode
 * <TagForm
 *   tag={existingTag}
 *   onSubmit={handleUpdate}
 *   onCancel={handleCancel}
 *   isLoading={isUpdating}
 * />
 * ```
 */
export function TagForm({
  tag,
  onSubmit,
  onCancel,
  isLoading = false,
  className = '',
}: TagFormProps): React.ReactElement {
  // Determine if we're in edit mode
  const isEditMode = Boolean(tag);

  // Notification context for showing success/error messages
  const { showSuccess, showError } = useNotification();

  // Build default values from existing entity or defaults
  const defaultValues = useMemo<Partial<TagFormData>>(() => {
    if (tag) {
      // Edit mode: use existing entity values
      return {
        name: tag.name,
        color: tag.color ?? '',
      };
    }
    // Create mode: use defaults
    return DEFAULT_FORM_VALUES;
  }, [tag]);

  // Initialize React Hook Form
  const methods = useForm<TagFormData>({
    defaultValues,
    mode: 'onBlur',
  });

  const {
    control,
    handleSubmit,
    formState: { errors },
    reset,
  } = methods;

  // Reset form when entity data changes (e.g., switching from create to edit mode)
  useEffect(() => {
    reset(defaultValues);
  }, [defaultValues, reset]);

  // Log validation errors to console for debugging
  useEffect(() => {
    if (Object.keys(errors).length > 0) {
      console.log('[TagForm] Validation errors:', errors);
    }
  }, [errors]);
  // -------------------------------------------------------------------------
  // Form Submission
  // -------------------------------------------------------------------------

  const handleFormSubmit = async (data: TagFormData) => {
    console.log('[TagForm] Submitting:', { data, isEditMode });
    try {
      const result = await onSubmit(data);
      console.log('[TagForm] Form submission successful', { data, result, isEditMode });
      // Show success notification for create operation
      if (!isEditMode) {
        showSuccess('Tag created successfully');
      }
    } catch (error) {
      // Log full error details to console for debugging
      console.error('[TagForm] Form submission failed', {
        error,
        errorMessage: error instanceof Error ? error.message : String(error),
        errorStack: error instanceof Error ? error.stack : undefined,
        data,
        isEditMode,
      });
      // Show error notification on failure
      const errorMessage = error instanceof Error ? error.message : 'An unexpected error occurred';
      showError(`Failed to ${isEditMode ? 'update' : 'create'} Tag: ${errorMessage}`);
    }
  };

  // -------------------------------------------------------------------------
  // Render
  // -------------------------------------------------------------------------

  // Count validation errors
  const errorCount = Object.keys(errors).length;

  return (
    <FormProvider {...methods}>
      <Box
        component="form"
        onSubmit={handleSubmit(handleFormSubmit)}
        className={className}
        data-testid="form-tag"
        noValidate
      >
        {/* Error Summary Alert */}
        {errorCount > 0 && (
          <MuiAlert
            severity="error"
            sx={{ mb: 3 }}
            data-testid="form-errors-summary"
          >
            Please fix {errorCount} error{errorCount !== 1 ? 's' : ''} before submitting
          </MuiAlert>
        )}

        <Grid container spacing={3}>
          {/* Name field */}
          <Grid size={{ xs: 12, md: 6 }}>
            {/* 4. Default: plain text field */}
            <Controller
              name="name"
              control={control}
              rules={{
                required: 'Name is required',
                maxLength: { value: 100, message: 'Name must be at most 100 characters' },
              }}
              render={({ field: formField, fieldState }) => (
                <TextField
                  {...formField}
                  label="Name"
                  fullWidth
                  required
                  disabled={isLoading}
                  error={!!fieldState.error}
                  helperText={fieldState.error?.message}
                  placeholder=""
                  value={formField.value || ''}
                  data-testid="field-name"
                />
              )}
            />
          </Grid>

          {/* Color field */}
          <Grid size={{ xs: 12, md: 6 }}>
            {/* 4. Default: plain text field */}
            <Controller
              name="color"
              control={control}
              rules={{
                required: 'Color is required',
                maxLength: { value: 20, message: 'Color must be at most 20 characters' },
              }}
              render={({ field: formField, fieldState }) => (
                <TextField
                  {...formField}
                  label="Color"
                  fullWidth
                  required
                  disabled={isLoading}
                  error={!!fieldState.error}
                  helperText={fieldState.error?.message || "Hex color code"}
                  placeholder=""
                  value={formField.value || ''}
                  data-testid="field-color"
                />
              )}
            />
          </Grid>

          {/* Form Actions */}
          <Grid size={12}>
            <Box display="flex" gap={2} pt={2}>
              <Button
                type="submit"
                variant="contained"
                color="primary"
                disabled={isLoading}
                startIcon={isLoading ? <CircularProgress size={20} /> : undefined}
                data-testid="submit-button"
              >
                {isLoading
                  ? 'Saving...'
                  : isEditMode
                    ? 'Update Tag'
                    : 'Create Tag'}
              </Button>

              <Button
                type="button"
                variant="outlined"
                onClick={onCancel}
                disabled={isLoading}
                data-testid="cancel-button"
              >
                Cancel
              </Button>
            </Box>
          </Grid>
        </Grid>
      </Box>
    </FormProvider>
  );
}

