/**
 * TagFormModal Component
 *
 * Wraps the TagForm in a Material UI Dialog for modal display.
 * Use this component when you want to show the form in a popup dialog.
 *
 * @example
 * ```tsx
 * <TagFormModal
 *   open={isModalOpen}
 *   onClose={handleClose}
 *   onSubmit={handleCreate}
 *   onCancel={handleClose}
 *   isLoading={isCreating}
 * />
 * ```
 */
export function TagFormModal({
  open,
  onClose,
  title,
  tag,
  onSubmit,
  onCancel,
  isLoading = false,
  className = '',
}: TagFormModalProps): React.ReactElement {
  const isEditMode = Boolean(tag);
  const modalTitle = title ?? (isEditMode ? 'Edit Tag' : 'Create Tag');

  // Handle modal close - prevent closing during loading
  const handleClose = () => {
    if (!isLoading) {
      onClose();
    }
  };

  return (
    <Dialog
      open={open}
      onClose={handleClose}
      maxWidth="md"
      fullWidth
      data-testid="modal-tag-form"
    >
      <DialogTitle sx={{ m: 0, p: 2, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        {modalTitle}
        <IconButton
          aria-label="close"
          onClick={handleClose}
          disabled={isLoading}
          data-testid="modal-close-button"
          sx={{ color: (theme) => theme.palette.grey[500] }}
        >
          <CloseIcon />
        </IconButton>
      </DialogTitle>
      <DialogContent dividers>
        <TagForm
          tag={tag}
          onSubmit={onSubmit}
          onCancel={onCancel}
          isLoading={isLoading}
          className={className}
        />
      </DialogContent>
    </Dialog>
  );
}


// Default export for convenience
export default TagForm;
